/**
 * @summary Get active rentals
 */
export const getGetRentalsUrl = (params?: GetRentalsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/rentals?${stringifiedParams}`
    : `/api/rentals`;
};

export const getRentals = async (
  params?: GetRentalsParams,
  options?: RequestInit,
): Promise<Rental[]> => {
  return customFetch<Rental[]>(getGetRentalsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetRentalsQueryKey = (params?: GetRentalsParams) => {
  return [`/api/rentals`, ...(params ? [params] : [])] as const;
};

